css:
.print-format .table-bordered,
.print-format .table-bordered th,
.print-format .table-bordered td {
    border: 1px solid #000 !important;
}

/* Viền ngoài bảng đậm hơn chút cho rõ khung */
.print-format .table-bordered {
    border: 1.5px solid #000 !important;
}

/* === OT Registration V2 — footer === */
.ot-expl-line { margin: 6px 0 12px; white-space: nowrap; overflow: hidden; font-family: "Times New Roman", serif; }
.ot-approval { width: 100%; border-collapse: collapse; border: none; margin-top: 10px; text-align: center; font-family: "Times New Roman", serif; font-size: 11px; }
.ot-approval td { border: none !important; vertical-align: top; padding: 6px; width: 33.33%; }
.ot-approval .st { font-weight: bold; }
.ot-approval .st-vn { font-style: italic; color: #666; font-size: 9px; }
.ot-approval .gap { height: 55px; }
.ot-approval .role { font-weight: bold; }
.ot-approval .role-vn { font-style: italic; color: #666; font-size: 9px; }
.ot-approval .nm { font-weight: bold; margin-top: 4px; }

.print-format {
      margin-top: 5mm;
      margin-left: 5mm;
      margin-right: 5mm;
    /* margin-bottom: 25mm;   /* chừa chỗ cho footer "Page X of Y"  */
  }

